module counter8bit_up_sync (
    input clk,
    input rst,
    input en,
    output [7:0] q
);

    reg [7:0] q_reg;

    always @(posedge clk) begin
        if (rst)
            q_reg <= 8'b00000000;
        else if (en)
            q_reg <= q_reg + 1;
    end

    wire cnt_tmp = q_reg;
    assign q = cnt_tmp;

endmodule
